const isHealthCheckProbe = healthProbeValues.includes(requestedServiceProbe)
  || healthProbeValues.includes(eventTypeProbe)
  || emailProbe === 'healthcheck@thegtcollective.com'
  || emailProbe === 'healthcheck@example.invalid'
  || emailProbe === 'ops-probe@example.com'
  || (nameProbe.includes('health') && nameProbe.includes('check'))
  || notesProbe.includes('webhook registration probe')
  || notesProbe.includes('automated registration probe');
if (isHealthCheckProbe) {
  const probe = {
    timestamp: new Date().toISOString(),
    status: 'Ignored Health Check',
    reason: 'automation_health_check',
    requested_service: requestedServiceProbe || 'health_check',
    source_site: cleanInput(b.source_site || b.site),
    page_url: cleanInput(b.page_url || b.source_url || b.landing_url),
