  return [{
    json: {
      valid_intake: false,
      ok: true,
      ignored: true,
      ...probe,
      responseBody: {
        ok: true,
        ignored: true,
        reason: probe.reason,
        message: 'Health check accepted; no customer workflow was created.'
      }
    },
    binary: {
      data: {
        data: Buffer.from(JSON.stringify(probe) + '\n').toString('base64'),
        mimeType: 'application/jsonl',
        fileName: 'service-request-healthcheck.jsonl',
      },
    },
  }];
}
const turnstileResult = $json || {};
